static uint32_t normalize(uint32_t addr) {
    uint32_t phys = addr & 0x1FFFFFFFu;
    /* Kernel Part 2: ROM 0x1FC10000+ -> RAM 0x500+ */
    if (phys >= 0x1FC10000u && phys <= 0x1FC17FFFu)
        phys = phys - 0x1FC10000u + 0x00000500u;
    /* Shell: RAM 0x30000+ -> ROM physical 0x1FC18000+ */
    if (phys >= 0x00030000u && phys <= 0x0005AFFFu)
        phys = phys - 0x00030000u + 0x1FC18000u;
    return phys;
}

extern int dirty_ram_dispatch(CPUState* cpu, uint32_t addr);
extern void fntrace_record(CPUState* cpu, uint32_t target);

void psx_dispatch(CPUState* cpu, uint32_t addr) {
    /* Tail-call trampoline: functions signal tail calls by setting
     * cpu->pc to the target and returning. We loop here to re-dispatch
     * without growing the native stack. */
    for (;;) {
        /* Always-on call ring: every iteration counts as a separate
         * call (initial entry + each tail-call re-dispatch). a0..a3
         * reflect the args being passed for THIS iteration. */
        fntrace_record(cpu, addr);
        cpu->pc = 0;
        uint32_t phys = normalize(addr);
        int lo = 0, hi = 4390 - 1;
        int found = 0;
        while (lo <= hi) {
            int mid = (lo + hi) / 2;
            if (dispatch_table[mid].addr == phys) {
                g_debug_current_func_addr = phys;
                debug_server_trace_dispatch(phys);
                dispatch_table[mid].func(cpu);
                found = 1;
                break;
            } else if (dispatch_table[mid].addr < phys) {
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        /* Static dispatch miss.  Self-modifying / install-at-runtime RAM
         * (CLAUDE.md Rule 18): the BIOS writes dispatch stubs into kernel
         * RAM at runtime.  If the target page has been written-to since
         * boot, interpret the basic block on cpu state.  Falls back to
         * psx_unknown_dispatch for genuinely unmapped PCs. */
        if (!found) {
            if (dirty_ram_dispatch(cpu, addr)) {
                found = 1;
            } else {
                psx_unknown_dispatch(cpu, addr, phys);
            }
        }
        if (cpu->pc == 0) { psx_check_interrupts(cpu); return; }
        addr = cpu->pc;  /* tail call: re-dispatch */
    }
}
